const raw = $input.first().json.output;

// Strip any accidental markdown fences
const cleaned = raw.replace(/```json|```/g, '').trim();

const email = JSON.parse(cleaned);

// Fallback if no contact found
email.display_name = email.to_name || email.company;
email.recipient = email.to_email || 'team@' + email.company.toLowerCase().replace(/\s+/g, '') + '.com';

return [{ json: email }];
